using System.ComponentModel.DataAnnotations;

namespace sv_68221a40b67e413eaadc4f55d7436769.Models;

public class ReviewModel
{
    [Required(ErrorMessage = "Product name is required.")]
    public string ProductName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Rating is required.")]
    [Range(1, 5, ErrorMessage = "Rating must be between 1 and 5.")]
    public int? Rating { get; set; }

    [Required(ErrorMessage = "Review title is required.")]
    [MaxLength(100, ErrorMessage = "Review title cannot exceed 100 characters.")]
    public string ReviewTitle { get; set; } = string.Empty;

    [Required(ErrorMessage = "Review body is required.")]
    [MaxLength(2000, ErrorMessage = "Review body cannot exceed 2000 characters.")]
    public string ReviewBody { get; set; } = string.Empty;
}

using sv_68221a40b67e413eaadc4f55d7436769.Models;

namespace sv_68221a40b67e413eaadc4f55d7436769.Services;

public class ReviewService
{
    /// <summary>
    /// Validates the review against server-side business rules and submits it.
    /// Returns a dictionary of field-specific errors (field name → error message).
    /// An empty dictionary means the review was accepted.
    /// </summary>
    public Task<Dictionary<string, string>> ValidateAndSubmitAsync(
        ReviewModel review, IReadOnlyList<PhotoInfo>? photos)
    {
        var errors = new Dictionary<string, string>();

        if (review.ReviewTitle.Contains("spam", StringComparison.OrdinalIgnoreCase))
        {
            errors[nameof(review.ReviewTitle)] = "Review title contains inappropriate language.";
        }

        // TODO: persist the review and photos when a real back-end is available.

        return Task.FromResult(errors);
    }
}

public record PhotoInfo(string FileName, long SizeBytes, byte[] Content, string ContentType);

@page "/write-review"
@rendermode InteractiveServer
@using sv_68221a40b67e413eaadc4f55d7436769.Models
@using sv_68221a40b67e413eaadc4f55d7436769.Services
@inject ReviewService ReviewService

<PageTitle>Write a Review</PageTitle>

<h1>Write a Review</h1>

@if (submitted)
{
    <div class="alert alert-success" role="alert">
        <h4 class="alert-heading">Thank you!</h4>
        <p>Your review has been submitted successfully.</p>
    </div>
}
else
{
    <EditForm Model="model" OnValidSubmit="HandleSubmitAsync" FormName="write-review">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="productName" class="form-label">Product Name</label>
            <InputText id="productName" class="form-control" @bind-Value="model.ProductName" />
            <ValidationMessage For="() => model.ProductName" />
            @if (serverErrors.ContainsKey(nameof(model.ProductName)))
            {
                <div class="validation-message">@serverErrors[nameof(model.ProductName)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="rating" class="form-label">Rating</label>
            <InputNumber id="rating" class="form-control" @bind-Value="model.Rating" min="1" max="5" />
            <ValidationMessage For="() => model.Rating" />
            @if (serverErrors.ContainsKey(nameof(model.Rating)))
            {
                <div class="validation-message">@serverErrors[nameof(model.Rating)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="reviewTitle" class="form-label">Review Title</label>
            <InputText id="reviewTitle" class="form-control" @bind-Value="model.ReviewTitle" maxlength="100" />
            <ValidationMessage For="() => model.ReviewTitle" />
            @if (serverErrors.ContainsKey(nameof(model.ReviewTitle)))
            {
                <div class="validation-message">@serverErrors[nameof(model.ReviewTitle)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="reviewBody" class="form-label">Review Body</label>
            <InputTextArea id="reviewBody" class="form-control" @bind-Value="model.ReviewBody" rows="5" maxlength="2000" />
            <ValidationMessage For="() => model.ReviewBody" />
            @if (serverErrors.ContainsKey(nameof(model.ReviewBody)))
            {
                <div class="validation-message">@serverErrors[nameof(model.ReviewBody)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="photos" class="form-label">Photos (up to 3, JPG/PNG, max 5 MB each)</label>
            <InputFile id="photos" class="form-control" OnChange="OnPhotosSelected"
                       multiple accept=".jpg,.jpeg,.png" />
            @if (!string.IsNullOrEmpty(photoError))
            {
                <div class="validation-message">@photoError</div>
            }

            @if (uploadedPhotos.Count > 0)
            {
                <ul class="list-group mt-2">
                    @foreach (var photo in uploadedPhotos)
                    {
                        <li class="list-group-item d-flex justify-content-between align-items-center">
                            @photo.FileName
                            <span class="badge bg-secondary">@FormatSize(photo.SizeBytes)</span>
                        </li>
                    }
                </ul>
            }
        </div>

        <button type="submit" class="btn btn-primary" disabled="@isSubmitting">
            @if (isSubmitting)
            {
                <span class="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
                <text> Submitting…</text>
            }
            else
            {
                <text>Submit Review</text>
            }
        </button>
    </EditForm>
}

@code {
    private ReviewModel model = new();
    private List<PhotoInfo> uploadedPhotos = new();
    private Dictionary<string, string> serverErrors = new();
    private string? photoError;
    private bool submitted;
    private bool isSubmitting;

    private const long MaxFileSize = 5 * 1024 * 1024; // 5 MB
    private const int MaxFileCount = 3;
    private static readonly string[] AllowedContentTypes = ["image/jpeg", "image/png"];

    private async Task OnPhotosSelected(InputFileChangeEventArgs e)
    {
        photoError = null;
        uploadedPhotos.Clear();

        if (e.FileCount > MaxFileCount)
        {
            photoError = $"You can upload at most {MaxFileCount} photos.";
            return;
        }

        foreach (var file in e.GetMultipleFiles(MaxFileCount))
        {
            if (!AllowedContentTypes.Contains(file.ContentType))
            {
                photoError = $"'{file.Name}' is not a supported format. Only JPG and PNG are allowed.";
                uploadedPhotos.Clear();
                return;
            }

            if (file.Size > MaxFileSize)
            {
                photoError = $"'{file.Name}' exceeds the 5 MB size limit.";
                uploadedPhotos.Clear();
                return;
            }

            using var stream = file.OpenReadStream(maxAllowedSize: MaxFileSize);
            using var ms = new MemoryStream();
            await stream.CopyToAsync(ms);

            uploadedPhotos.Add(new PhotoInfo(file.Name, file.Size, ms.ToArray(), file.ContentType));
        }
    }

    private async Task HandleSubmitAsync()
    {
        serverErrors.Clear();
        isSubmitting = true;

        try
        {
            var errors = await ReviewService.ValidateAndSubmitAsync(model, uploadedPhotos);

            if (errors.Count > 0)
            {
                serverErrors = errors;
                return;
            }

            submitted = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private static string FormatSize(long bytes) => bytes switch
    {
        < 1024 => $"{bytes} B",
        < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
        _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
    };
}

